#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define N 200005

int T, n, a[N], s[N], cnt[N], sum;

int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (int i = 1; i <= n; i++) {
            scanf("%d", &a[i]);
            s[i] = s[i - 1] + a[i];
            cnt[s[i]]++;
        }
        sum = 0;
        for (int i = 1; i <= n; i++) {
            sum += cnt[s[i] - s[i - 1]];
        }
        printf("%d\n", sum);
    }
    return 0;
}

